patch:
--- a/decoder.sv
+++ b/decoder.sv
@@ -1,15 +1,15 @@
 module decoder_2to4(
-  output logic [3:0] enable,
   input [1:0] addr,
+  output logic [3:0] enable,
   input active
 );
   always_comb begin
     enable = '0;
     if(active) enable[addr] = 1'b1;
   end
 endmodule

 module system;
   logic [1:0] address;
   logic enable_in;
   logic [3:0] output_lines;
   decoder_2to4 dec_inst(.addr(address), .active(enable_in), .enable(output_lines));
 endmodule

